import vex
import re

@vex.listener
def validate_financial_tools(event):
    if event.type == 'tool_call':
        # PCI DSS card patterns
        card_pattern = re.compile(r'\b(?:4[0-9]{12}(?:[0-9]{3})?|5[1-5][0-9]{14})\b')
        if card_pattern.search(event.input):
            vex.block('PCI_DSS_VIOLATION: Unencrypted card data in tool input')
        # SQL injection protection
        if 'UNION SELECT' in event.input.upper():
            vex.block('TOOL_INJECTION: Malicious SQL detected')

agent.add_event_listener(validate_financial_tools)

@vex.listener
def enforce_sec_disclaimers(event):
    if event.type == 'model_output' and 'financial advice' in event.prompt.lower():
        granite_output = event.output
        # Fix Granite format inconsistencies
        if not granite_output.get('structured'):
            vex.alert('Granite format error - missing structured response')

        disclaimer = "\n\n⚠️ SEC DISCLAIMER: This is not personalized financial advice. Past performance doesn't guarantee future results. Consult qualified advisor."
        event.output['content'] += disclaimer
        event.output['compliance_flags'] = ['SEC_REG_BI_APPLIED']

agent.add_event_listener(enforce_sec_disclaimers)
vex.record_event(event)
